import {
  createSurfaceEffect,
  createSurfaceSource,
  fieldLayout,
  recoverableDamage,
  threeInstancedMeshRenderer,
} from 'weft-sdk/three'
import { seedCursor } from 'weft-sdk/core'

const emberSurface = createSurfaceSource({
  cacheKey: 'ember-band',
  units: ['.', '*', '•'],
  repeat: 20,
})

const emberEffect = createSurfaceEffect({
  id: 'ember-band',
  source: emberSurface,
  seedCursor,
  layout: fieldLayout({
    rows: 20,
    sectors: 32,
    advanceForRow: (row) => row * 11 + 3,
    staggerFactor: 0.4,
    minSpanFactor: 0.3,
  }),
  renderer: threeInstancedMeshRenderer({
    geometry: new THREE.PlaneGeometry(0.16, 0.16),
    material: new THREE.MeshBasicMaterial({ color: '#ff8a44' }),
    maxInstances: 2400,
  }),
  behaviors: [
    recoverableDamage({
      radius: 1.2,
      recoveryRate: 0.35,
    }),
  ],
})

